        p.append(p[i-1] * 2)
    hr = '12345RGBYW'
    gt = {'1': 0, '2': 1, '3': 2, '4': 3, '5': 4, 'R': 5, 'G': 6, 'B': 7, 'Y': 8, 'W': 9}

    def check(c, mask):
        tmp = gt[c]
